import{_ as a,o as r,c as e,ae as l}from"./chunks/framework.BeMCGcrk.js";const p=JSON.parse('{"title":"2026年5月19日科技股日报：阿里FY26年报发布、美团算法升级、小米汽车再破2万","description":"","frontmatter":{},"headers":[],"relativePath":"blog/2026-05-19-tech-stocks-daily.md","filePath":"blog/2026-05-19-tech-stocks-daily.md"}'),o={name:"blog/2026-05-19-tech-stocks-daily.md"};function d(h,t,i,n,s,c){return r(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="_2026年5月19日科技股日报-阿里fy26年报发布、美团算法升级、小米汽车再破2万" tabindex="-1">2026年5月19日科技股日报：阿里FY26年报发布、美团算法升级、小米汽车再破2万 <a class="header-anchor" href="#_2026年5月19日科技股日报-阿里fy26年报发布、美团算法升级、小米汽车再破2万" aria-label="Permalink to &quot;2026年5月19日科技股日报：阿里FY26年报发布、美团算法升级、小米汽车再破2万&quot;">​</a></h1><p><strong>2026年5月19日</strong> - 今日科技股重点关注：阿里巴巴FY2026财年年报正式出炉，全年营收站上万亿台阶但净利润承压；美团推出13项算法优化举措；小米汽车月交付量连续突破2万台，新一代SU7上市即热销。</p><hr><h2 id="阿里巴巴-9988-hk-baba-us-fy2026营收首破万亿-ai战略加速" tabindex="-1">阿里巴巴（9988.HK / BABA.US）：FY2026营收首破万亿，AI战略加速 <a class="header-anchor" href="#阿里巴巴-9988-hk-baba-us-fy2026营收首破万亿-ai战略加速" aria-label="Permalink to &quot;阿里巴巴（9988.HK / BABA.US）：FY2026营收首破万亿，AI战略加速&quot;">​</a></h2><h3 id="重大事件" tabindex="-1">重大事件 <a class="header-anchor" href="#重大事件" aria-label="Permalink to &quot;重大事件&quot;">​</a></h3><p><strong>5月13日，阿里巴巴发布FY2026全年及Q4财报（截至2026年3月31日）</strong></p><p><strong>财务数据：</strong></p><table tabindex="0"><thead><tr><th>指标</th><th>FY2026全年</th><th>同比</th></tr></thead><tbody><tr><td>总收入</td><td>1.02万亿元</td><td>+3%</td></tr><tr><td>经营利润</td><td>501.5亿元</td><td>-64%</td></tr><tr><td>净利润</td><td>1059.04亿元</td><td>-18%</td></tr></tbody></table><p><strong>Q4单季数据：</strong></p><ul><li>收入 2433.80亿元（约352.83亿美元），同比增长3%</li><li>同口径（剔除已处置业务）增长更高</li><li>EPS 3.83元，同比减少约26%</li></ul><p><strong>利润下滑主因：</strong> 战略投入加大（AI、云计算、全球化），以及一次性减值准备。</p><h3 id="ai战略持续深化" tabindex="-1">AI战略持续深化 <a class="header-anchor" href="#ai战略持续深化" aria-label="Permalink to &quot;AI战略持续深化&quot;">​</a></h3><ul><li>近期密集发布多款AI大模型，涵盖通义千问系列企业级应用</li><li>阿里云保持国内公有云市场领先地位，AI算力需求旺盛</li><li>夸克AI搜索用户量持续攀升</li><li>机构关注度高，&quot;AI+云&quot;组合被视为价值重估核心逻辑</li></ul><h3 id="投资观点" tabindex="-1">投资观点 <a class="header-anchor" href="#投资观点" aria-label="Permalink to &quot;投资观点&quot;">​</a></h3><p>FY2026营收破万亿具有里程碑意义，但利润端承压反映转型期投入力度。AI是最大看点，云计算增速是后续关键观察指标。建议关注Q4财报电话会管理层指引。</p><blockquote><p>来源：<a href="https://www.ithome.com/0/949/981.htm" target="_blank" rel="noreferrer">IT之家</a>、<a href="https://www.cww.net.cn/article?id=609577" target="_blank" rel="noreferrer">通信世界网</a>、<a href="https://news.qq.com/rain/a/20260513A08LAZ00" target="_blank" rel="noreferrer">腾讯新闻</a></p></blockquote><hr><h2 id="美团-3690-hk-发布13项算法优化-回应社会关切" tabindex="-1">美团（3690.HK）：发布13项算法优化，回应社会关切 <a class="header-anchor" href="#美团-3690-hk-发布13项算法优化-回应社会关切" aria-label="Permalink to &quot;美团（3690.HK）：发布13项算法优化，回应社会关切&quot;">​</a></h2><h3 id="重大事件-1" tabindex="-1">重大事件 <a class="header-anchor" href="#重大事件-1" aria-label="Permalink to &quot;重大事件&quot;">​</a></h3><p><strong>5月8日，美团发布2026年算法机制优化公告，推出13项改进措施</strong></p><p><strong>五大方向：</strong></p><ol><li><strong>算法透明度提升</strong> — 向骑手公开派单逻辑说明</li><li><strong>派单公平性优化</strong> — 减少歧视性规则，建立申诉机制</li><li><strong>骑手权益保障</strong> — 最低收入保障、超时处罚豁免情形扩大</li><li><strong>安全合规管理</strong> — 疲劳度监控强化，降速提醒机制</li><li><strong>三方共赢生态</strong> — 商家、骑手、平台利益平衡机制</li></ol><p>此次升级遵循&quot;生活服务类平台算法负面清单（试行）&quot;，具有示范意义。</p><h3 id="_2025年财报回顾-3月26日发布" tabindex="-1">2025年财报回顾（3月26日发布） <a class="header-anchor" href="#_2025年财报回顾-3月26日发布" aria-label="Permalink to &quot;2025年财报回顾（3月26日发布）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>2025全年</th><th>同比</th></tr></thead><tbody><tr><td>总收入</td><td>3649亿元</td><td>+8%</td></tr><tr><td>净利润</td><td><strong>-234亿元</strong></td><td>由盈转亏</td></tr></tbody></table><p><strong>亏损原因：</strong> 即时零售&quot;内卷式&quot;竞争（主要来自京东外卖、抖音等），补贴战拖累利润。</p><p><strong>市场份额：</strong> 外卖GTV占比维持60%以上，护城河依然深厚。</p><h3 id="投资观点-1" tabindex="-1">投资观点 <a class="header-anchor" href="#投资观点-1" aria-label="Permalink to &quot;投资观点&quot;">​</a></h3><p>外卖价格战后遗症仍在消化，234亿亏损超出市场预期。但核心业务壁垒未受根本撼动，算法升级有助于改善骑手关系和ESG形象。关注Q2起竞争趋缓信号及新业务减亏节奏。</p><blockquote><p>来源：<a href="https://news.zol.com.cn/1177/11773599.html" target="_blank" rel="noreferrer">中关村在线</a>、<a href="http://www.eeo.com.cn/2026/0326/818945.shtml" target="_blank" rel="noreferrer">经济观察网</a>、<a href="https://finance.sina.com.cn/wm/2026-03-26/doc-inhsiusr8822921.shtml" target="_blank" rel="noreferrer">新浪财经</a></p></blockquote><hr><h2 id="小米-1810-hk-3月交付破2万-新一代su7上市即爆" tabindex="-1">小米（1810.HK）：3月交付破2万，新一代SU7上市即爆 <a class="header-anchor" href="#小米-1810-hk-3月交付破2万-新一代su7上市即爆" aria-label="Permalink to &quot;小米（1810.HK）：3月交付破2万，新一代SU7上市即爆&quot;">​</a></h2><h3 id="重大事件-2" tabindex="-1">重大事件 <a class="header-anchor" href="#重大事件-2" aria-label="Permalink to &quot;重大事件&quot;">​</a></h3><p><strong>3月19日，小米举办春季新品发布会，新一代SU7正式上市</strong></p><ul><li>发布会19:00正式开始，新一代SU7是绝对主角</li><li>3月23日开始交付，9天累计交付超7000台，日均交付近800台</li><li>当月全系交付量超过2万台</li></ul><p><strong>3月9日，小米启动2026届春季校园招聘</strong>，面向应届生开放AI研发、产品等100+岗位。</p><h3 id="汽车销量数据" tabindex="-1">汽车销量数据 <a class="header-anchor" href="#汽车销量数据" aria-label="Permalink to &quot;汽车销量数据&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时间</th><th>车型</th><th>销量/交付量</th></tr></thead><tbody><tr><td>2026年1月</td><td>YU7</td><td>37,869台（月销冠）</td></tr><tr><td>2026年2月</td><td>全系</td><td>突破2万台</td></tr><tr><td>2026年3月</td><td>SU7（新款）</td><td>9天交付7000+台</td></tr><tr><td>2025全年</td><td>SU7</td><td>20万以上轿车销量第一</td></tr></tbody></table><p><strong>市场表现：</strong></p><ul><li>YU7（中大型纯电SUV）上市6个月，连续5个月中大型SUV销冠</li><li>SU7全年稳居20万以上轿车榜首</li><li>新一代SU7接力，订单持续饱满</li></ul><h3 id="投资观点-2" tabindex="-1">投资观点 <a class="header-anchor" href="#投资观点-2" aria-label="Permalink to &quot;投资观点&quot;">​</a></h3><p>小米汽车已经证明了自己——两款车均成为细分市场爆款。产能是当前主要约束，建议关注：</p><ol><li>新一代SU7产能爬坡进度</li><li>YU7出口计划（若有）</li><li>智驾功能迭代进展</li></ol><blockquote><p>来源：<a href="https://news.china.com/socialgd/10000169/20260403/49383480.html" target="_blank" rel="noreferrer">中华网</a>、<a href="https://www.dongchedi.com/article/7612594027657626136" target="_blank" rel="noreferrer">懂车帝</a>、<a href="https://m.pcauto.com.cn/x/5133/51330171.html" target="_blank" rel="noreferrer">太平洋汽车</a></p></blockquote><hr><h2 id="今日总结" tabindex="-1">今日总结 <a class="header-anchor" href="#今日总结" aria-label="Permalink to &quot;今日总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公司</th><th>评级</th><th>核心逻辑</th><th>关注风险</th></tr></thead><tbody><tr><td>阿里巴巴</td><td>中性偏多</td><td>AI+云战略、估值修复</td><td>利润压力、竞争加剧</td></tr><tr><td>美团</td><td>中性</td><td>市场份额稳固、竞争趋缓</td><td>外卖价格战、减亏进度</td></tr><tr><td>小米</td><td>看好</td><td>汽车爆款、产能释放、生态协同</td><td>汽车毛利率、价格战</td></tr></tbody></table><hr><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><ul><li>市场系统性风险</li><li>监管政策变化</li><li>竞争格局恶化</li><li>技术迭代不及预期</li></ul><p><strong>免责声明：本文仅供参考，不构成投资建议。投资有风险，入市需谨慎。</strong></p><hr><p><em>本文写于 2026年5月19日</em></p>',53)])])}const u=a(o,[["render",d]]);export{p as __pageData,u as default};
